import argparse
import json
import os
import numpy as np
import heapq
import torch
from cogniplan_env import ExplorationEnv


def dijkstra(adj, start):
    N = len(adj)
    dist = [float('inf')] * N
    prev = [None] * N
    dist[start] = 0.0
    pq = [(0.0, start)]
    while pq:
        d, u = heapq.heappop(pq)
        if d > dist[u] + 1e-9:
            continue
        for v, w in adj[u]:
            nd = d + w
            if nd + 1e-9 < dist[v]:
                dist[v] = nd
                prev[v] = u
                heapq.heappush(pq, (nd, v))
    return dist, prev


def bfs_hops(adj, start):
    N = len(adj)
    hops = [float('inf')] * N
    hops[start] = 0
    q = [start]
    for u in q:
        for v, _ in adj[u]:
            if hops[v] == float('inf'):
                hops[v] = hops[u] + 1
                q.append(v)
    return hops


def round_coord(c):
    return tuple(np.round(np.array(c, dtype=float), 6))


def build_graph(nodes, robot_pos, neighbors):
    coord_to_idx = {}
    for i, n in enumerate(nodes):
        coord_to_idx[round_coord(n["coords"])] = i
    N = len(nodes)
    adj = [[] for _ in range(N)]
    for i, n in enumerate(nodes):
        for nb in n.get("neighbors", []):
            j = None
            if isinstance(nb, dict):
                nb = nb.get("coords", nb)
            if isinstance(nb, (list, tuple, np.ndarray)):
                j = coord_to_idx.get(round_coord(nb))
            else:
                try:
                    j = int(nb)
                    if not (0 <= j < N):
                        j = None
                except (ValueError, TypeError):
                    j = None
            if j is not None and j != i:
                w = float(np.linalg.norm(
                    np.array(n["coords"], dtype=float) -
                    np.array(nodes[j]["coords"], dtype=float)
                ))
                adj[i].append((j, w))
    r_idx = N
    adj.append([])
    for nb in neighbors:
        j = coord_to_idx.get(round_coord(nb))
        if j is None:
            continue
        w = float(np.linalg.norm(
            np.array(robot_pos, dtype=float) -
            np.array(nb, dtype=float)
        ))
        adj[r_idx].append((j, w))
        adj[j].append((r_idx, w))
    return adj, coord_to_idx, r_idx


class CleanPlanner:
    def __init__(self, dist_denom=3.6, reverse_penalty=0.3):
        self.dist_denom = dist_denom
        self.reverse_penalty = reverse_penalty
        self.reset()

    def reset(self):
        self.step_count = 0
        self.prev_pos = None

    def plan(self, obs):
        self.step_count += 1
        robot_pos = np.array(obs["robot_pos"], dtype=float)
        nodes = obs["nodes"]
        neighbors = obs["neighbors"]
        frontiers = obs.get("frontiers", [])

        if not neighbors:
            return None

        adj, coord_to_idx, r_idx = build_graph(nodes, robot_pos, neighbors)
        dist, prev = dijkstra(adj, r_idx)
        hops = bfs_hops(adj, r_idx)
        N = len(nodes)

        node_to_nb = {}
        for idx, nb in enumerate(neighbors):
            j = coord_to_idx.get(round_coord(nb))
            if j is not None:
                node_to_nb[j] = idx

        first_step = {}
        for j in range(N):
            if dist[j] == float('inf') or prev[j] is None:
                continue
            cur = j
            depth = 0
            while prev[cur] != r_idx and prev[cur] is not None and depth < N + 5:
                cur = prev[cur]
                depth += 1
            if prev[cur] == r_idx and cur in node_to_nb:
                first_step[j] = node_to_nb[cur]

        # Anti-backtracking: identify the neighbor that reverses previous motion
        reverse_idx = None
        if self.prev_pos is not None:
            prev_vec = robot_pos - np.array(self.prev_pos, dtype=float)
            prev_norm = np.linalg.norm(prev_vec)
            if prev_norm > 0.01:
                best_dot = float('inf')
                for idx, nb in enumerate(neighbors):
                    nb_vec = np.array(nb, dtype=float) - robot_pos
                    dot = np.dot(prev_vec, nb_vec)
                    if dot < best_dot:
                        best_dot = dot
                        reverse_idx = idx

        remaining_steps = 128 - self.step_count
        best_score = -float('inf')
        best_j = None

        # Primary: nodes with positive utility
        for j in range(N):
            if j not in first_step:
                continue
            utility = float(nodes[j].get("utility", 0.0))
            if utility <= 0:
                continue
            d = dist[j]
            h = hops[j] if hops[j] != float('inf') else max(d / 3.6, 1.0)
            if h > remaining_steps:
                continue
            score = utility / (d + self.dist_denom)
            if first_step[j] == reverse_idx:
                score *= self.reverse_penalty
            if score > best_score:
                best_score = score
                best_j = j

        # Fallback 1: unvisited nodes with zero utility (may reveal new areas)
        if best_j is None:
            for j in range(N):
                if j not in first_step:
                    continue
                if nodes[j].get("visited", False):
                    continue
                d = dist[j]
                h = hops[j] if hops[j] != float('inf') else max(d / 3.6, 1.0)
                if h > remaining_steps:
                    continue
                score = 0.1 / (d + self.dist_denom)
                if first_step[j] == reverse_idx:
                    score *= self.reverse_penalty
                if score > best_score:
                    best_score = score
                    best_j = j

        # Fallback 2: move toward nearest frontier cell
        if best_j is None and frontiers:
            best_f = None
            best_fd = float('inf')
            for f in frontiers:
                fd = np.linalg.norm(np.array(f, dtype=float) - robot_pos)
                if fd < best_fd:
                    best_fd = fd
                    best_f = f
            if best_f is not None:
                best_nb = None
                best_nb_dist = float('inf')
                for idx, nb in enumerate(neighbors):
                    nbd = np.linalg.norm(np.array(nb, dtype=float) - np.array(best_f, dtype=float))
                    if nbd < best_nb_dist:
                        best_nb_dist = nbd
                        best_nb = idx
                if best_nb is not None:
                    target = neighbors[best_nb]
                    self.prev_pos = robot_pos.copy()
                    return target

        # Fallback 3: farthest non-reversing neighbor
        if best_j is None:
            best_nb = None
            best_dist = -float('inf')
            for idx, nb in enumerate(neighbors):
                if idx == reverse_idx:
                    continue
                d = np.linalg.norm(np.array(nb, dtype=float) - robot_pos)
                if d > best_dist:
                    best_dist = d
                    best_nb = idx
            if best_nb is not None:
                target = neighbors[best_nb]
                self.prev_pos = robot_pos.copy()
                return target
            if neighbors:
                target = neighbors[0]
                self.prev_pos = robot_pos.copy()
                return target
            return None

        target = neighbors[first_step[best_j]]
        self.prev_pos = robot_pos.copy()
        return target


def run_episode(env, planner):
    obs = env.reset()
    planner.reset()
    for step in range(128):
        target = planner.plan(obs)
        if target is None:
            break
        obs, info = env.step(target)
        if info.get("done", False):
            break
    return env.get_metrics()


def main():
    parser = argparse.ArgumentParser()
    parser.add_argument("--data_path", required=True)
    parser.add_argument("--checkpoint", required=True)
    parser.add_argument("--output", required=True)
    args = parser.parse_args()

    ckpt_path = os.path.join(args.checkpoint, "policy.pt")
    if os.path.exists(ckpt_path):
        _ = torch.load(ckpt_path, map_location="cpu")

    data_path = args.data_path
    eval_config_path = os.path.join(data_path, "eval_config.json")
    maps_dir = os.path.join(data_path, "maps_eval")

    episodes = []
    if os.path.exists(eval_config_path):
        with open(eval_config_path, "r") as f:
            config = json.load(f)
        if isinstance(config, list):
            episodes = config
        elif isinstance(config, dict):
            if "episodes" in config:
                episodes = config["episodes"]

    if not episodes:
        for sub in ["room", "tunnel", "outdoor"]:
            d = os.path.join(maps_dir, sub)
            if not os.path.isdir(d):
                continue
            for f in sorted(os.listdir(d)):
                if f.endswith(".png"):
                    episodes.append({
                        "map_path": os.path.join("maps_eval", sub, f),
                        "env_type": sub
                    })

    planner = CleanPlanner()
    per_episode = []

    for ep in episodes:
        map_path = os.path.join(data_path, ep["map_path"])
        env = ExplorationEnv(map_path=map_path)
        metrics = run_episode(env, planner)
        success = 1 if metrics.get("success", False) else 0
        distance = metrics.get("travel_distance", 0.0)
        explored = metrics.get("explored_rate", 0.0)
        per_episode.append({
            "map_path": ep["map_path"],
            "env_type": ep.get("env_type", "unknown"),
            "success": success,
            "travel_distance": distance,
            "explored_rate": explored
        })

    total = len(per_episode)
    explored_rate = sum(e["explored_rate"] for e in per_episode) / total if total > 0 else 0.0
    success_rate = sum(e["success"] for e in per_episode) / total if total > 0 else 0.0
    success_dists = [e["travel_distance"] for e in per_episode if e["success"]]
    travel_distance = sum(success_dists) / len(success_dists) if success_dists else 0.0

    per_type = {}
    for et in ["room", "tunnel", "outdoor"]:
        eps = [e for e in per_episode if e["env_type"] == et]
        if not eps:
            continue
        srate = sum(e["success"] for e in eps) / len(eps)
        erate = sum(e["explored_rate"] for e in eps) / len(eps)
        sdists = [e["travel_distance"] for e in eps if e["success"]]
        td = sum(sdists) / len(sdists) if sdists else 0.0
        per_type[et] = {
            "explored_rate": erate,
            "travel_distance": td,
            "success_rate": srate
        }

    result = {
        "explored_rate": explored_rate,
        "travel_distance": travel_distance,
        "success_rate": success_rate,
        "per_episode": per_episode,
        "per_type": per_type,
        "total_episodes": total
    }

    out_dir = os.path.dirname(args.output)
    if out_dir:
        os.makedirs(out_dir, exist_ok=True)
    with open(args.output, "w") as f:
        json.dump(result, f, indent=2)


if __name__ == "__main__":
    main()
